import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../api/axiosConfig';
import { Zap, TrendingUp, TrendingDown, ChevronLeft, ChevronRight, Activity, ShieldCheck, Box } from 'lucide-react';

const LiveMarketPage = () => {
    const { token } = useContext(AuthContext);

    const [history, setHistory] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [stocks, setStocks] = useState([]);
    const [isConnected, setIsConnected] = useState(false);

    useEffect(() => {
        const fetchVault = async () => {
            try {
                const res = await api.get('/portfolio/history');
                setHistory(res.data);
                if (res.data.length > 0) initializeStocks(res.data[0].holdings);
            } catch (err) { console.error("VAULT_OFFLINE"); }
        };
        fetchVault();
    }, []);

    const initializeStocks = (holdingsData) => {
        try {
            let tickers = typeof holdingsData === 'string' ? JSON.parse(holdingsData) : holdingsData;
            if (typeof tickers === 'string') tickers = JSON.parse(tickers);
            setStocks(tickers.map(t => ({ ticker: t, price: Math.floor(Math.random() * 2000) + 500, change: 0.00 })));
        } catch (e) { setStocks([]); }
    };

    useEffect(() => {
        if (!token) return;
        const ws = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);
        ws.onopen = () => setIsConnected(true);
        ws.onmessage = () => {
            setStocks(prev => prev.map(s => {
                const move = (Math.random() - 0.5) * 8;
                return { ...s, price: parseFloat((s.price + move).toFixed(2)), change: parseFloat(move.toFixed(2)) };
            }));
        };
        ws.onclose = () => setIsConnected(false);
        return () => ws.close();
    }, [token, currentIndex]);

    const navigate = (dir) => {
        let newIdx = currentIndex + dir;
        if (newIdx >= 0 && newIdx < history.length) {
            setCurrentIndex(newIdx);
            initializeStocks(history[newIdx].holdings);
        }
    };

    const activeNode = history[currentIndex];

    return (
        <div style={pageBackground}>
            <div style={centeredTerminal}>
                {/* ── Dashboard Header ── */}
                <div style={headerSection}>
                    <div style={navRow}>
                        <button onClick={() => navigate(1)} disabled={currentIndex === history.length - 1} style={navBtn}>
                            <ChevronLeft size={16}/> PREV
                        </button>
                        <div style={nodeTitleBox}>
                            <Box size={14} color="#10b981" />
                            <span style={nodeText}>{activeNode ? activeNode.goal : 'INITIALIZING...'}</span>
                        </div>
                        <button onClick={() => navigate(-1)} disabled={currentIndex === 0} style={navBtn}>
                            NEXT <ChevronRight size={16}/>
                        </button>
                    </div>

                    <div style={statusRow}>
                        <div style={statusBadge(isConnected)}>
                            <Activity size={12} /> {isConnected ? 'LIVE_UPLINK' : 'OFFLINE'}
                        </div>
                        <div style={riskBadge}>
                            <ShieldCheck size={12} /> NODE_RISK: {activeNode?.risk_score || 0}%
                        </div>
                        <div style={counterTag}>{currentIndex + 1} / {history.length}</div>
                    </div>
                </div>

                {/* ── Internal Scrollable Grid ── */}
                <div style={scrollArea}>
                    <div style={gridStyle}>
                        {stocks.map((stock, i) => (
                            <div key={i} style={stockCard(stock.change >= 0)}>
                                <div style={cardHeader}>
                                    <span style={tickerName}>{stock.ticker}</span>
                                    <Zap size={14} color={stock.change >= 0 ? "#10b981" : "#ef4444"} />
                                </div>
                                <div style={priceContainer}>
                                    <span style={priceLabel}>MARKET_VALUE</span>
                                    <span style={priceText}>₹{stock.price.toLocaleString()}</span>
                                </div>
                                <div style={changeRow(stock.change >= 0)}>
                                    {stock.change >= 0 ? <TrendingUp size={14}/> : <TrendingDown size={14}/>}
                                    <span>{stock.change >= 0 ? '+' : ''}{stock.change}%</span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );
};

/* --- Visual Styles --- */
const pageBackground = { 
    height: 'calc(100vh - 70px)', 
    background: '#07080a', 
    display: 'flex', 
    justifyContent: 'center', 
    alignItems: 'flex-start',
    padding: '40px 20px' // Creates breathing room around the terminal
};

const centeredTerminal = { 
    width: '100%',
    maxWidth: '1200px', 
    height: '100%',
    maxHeight: '800px', // Keeps the UI compact and non-infinite
    background: '#0a0b0e', 
    borderRadius: '24px',
    border: '1px solid #1a1d23',
    display: 'flex', 
    flexDirection: 'column', 
    overflow: 'hidden',
    boxShadow: '0 30px 60px rgba(0,0,0,0.6)'
};

const headerSection = { padding: '1.5rem 2rem', borderBottom: '1px solid #1a1d23' };
const navRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' };
const navBtn = { background: 'none', border: 'none', color: '#10b981', cursor: 'pointer', fontSize: '0.65rem', fontWeight: 800, fontFamily: 'monospace', display: 'flex', alignItems: 'center', gap: '5px' };
const nodeTitleBox = { display: 'flex', alignItems: 'center', gap: '12px', background: '#111318', padding: '8px 16px', borderRadius: '8px', border: '1px solid #1a1d23' };
const nodeText = { fontSize: '0.8rem', fontWeight: 700, color: '#fff' };

const statusRow = { display: 'flex', gap: '1.5rem', alignItems: 'center' };
const statusBadge = (on) => ({ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.55rem', fontWeight: 900, color: on ? '#10b981' : '#ef4444' });
const riskBadge = { display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.55rem', fontWeight: 900, color: '#666' };
const counterTag = { marginLeft: 'auto', fontSize: '0.6rem', color: '#10b981', background: 'rgba(16,185,129,0.1)', padding: '2px 8px', borderRadius: '4px' };

const scrollArea = { flex: 1, padding: '2rem', overflowY: 'auto' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', gap: '1.2rem' };

const stockCard = (up) => ({ padding: '1.4rem', background: '#111318', border: '1px solid #1a1d23', borderRadius: '16px', borderLeft: `4px solid ${up ? '#10b981' : '#ef4444'}` });
const cardHeader = { display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' };
const tickerName = { fontSize: '0.8rem', fontWeight: 900, color: '#10b981', fontFamily: 'monospace' };
const priceContainer = { display: 'flex', flexDirection: 'column', marginBottom: '0.8rem' };
const priceLabel = { fontSize: '0.5rem', color: '#444', fontWeight: 800 };
const priceText = { fontSize: '1.8rem', fontWeight: 900, color: '#fff', fontFamily: 'monospace' };
const changeRow = (up) => ({ color: up ? '#10b981' : '#ef4444', fontSize: '0.8rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '6px' });

export default LiveMarketPage;
